export function parseDate(s) {
  // Bug: splits on '/' but ISO dates use '-', so Number(parts) is NaN.
  const parts = String(s).split('/');
  return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])).getTime();
}

